import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Define a maximum buffer size to prevent buffer overflow
        int bufferSize = 10;

        // Truncate the input if it exceeds the buffer size
        String truncatedName = name.substring(0, Math.min(name.length(), bufferSize));

        char[] buffer = new char[bufferSize];

        // Copy the truncated user input into the buffer
        truncatedName.getChars(0, truncatedName.length(), buffer, 0);

        System.out.println("Welcome, " + new String(buffer));
    }
}

